import { Inference, Page } from "../../../v1/parsing/common/index.js";
import { BarcodeReaderV1Document } from "./barcodeReaderV1Document.js";
/**
 * Barcode Reader API version 1 inference prediction.
 */
export class BarcodeReaderV1 extends Inference {
    constructor(rawPrediction) {
        super(rawPrediction);
        /** The endpoint's name. */
        this.endpointName = "barcode_reader";
        /** The endpoint's version. */
        this.endpointVersion = "1";
        /** The document's pages. */
        this.pages = [];
        this.prediction = new BarcodeReaderV1Document(rawPrediction["prediction"]);
        rawPrediction["pages"].forEach((page) => {
            if (page.prediction !== undefined && page.prediction !== null &&
                Object.keys(page.prediction).length > 0) {
                this.pages.push(new Page(BarcodeReaderV1Document, page, page["id"], page["orientation"]));
            }
        });
    }
}
